changeSet.sql:
CREATE TABLE nexus.plans ( id BIGSERIAL NOT NULL, tenant_id TEXT NOT NULL, project TEXT NOT NULL DEFAULT '', query TEXT NOT NULL, plan_json TEXT NOT NULL, outcome TEXT DEFAULT 'success', tags TEXT NOT NULL DEFAULT '', created_at TIMESTAMPTZ NOT NULL, ttl INTEGER, name TEXT, verb TEXT, scope TEXT, dimensions TEXT, default_bindings TEXT, parent_dims TEXT, use_count INTEGER NOT NULL DEFAULT 0, last_used TIMESTAMPTZ, match_count INTEGER NOT NULL DEFAULT 0, match_conf_sum DOUBLE PRECISION NOT NULL DEFAULT 0.0, success_count INTEGER NOT NULL DEFAULT 0, failure_count INTEGER NOT NULL DEFAULT 0, scope_tags TEXT NOT NULL DEFAULT '', match_text TEXT NOT NULL DEFAULT '', disabled_at TIMESTAMPTZ, CONSTRAINT plans_pk PRIMARY KEY (id), -- General upsert key: (tenant_id, project, query) — same role as memory's (tenant_id, project, title) CONSTRAINT plans_tenant_project_query_uq UNIQUE (tenant_id, project, query) );
-- Partial unique index mirroring SQLite plan_library's UNIQUE (project, dimensions) -- NULL dimensions excluded (partial index WHERE dimensions IS NOT NULL) to match -- SQLite's NULL != NULL behaviour for partial unique checks. CREATE UNIQUE INDEX idx_plans_tenant_dimensions ON nexus.plans (tenant_id, project, dimensions) WHERE dimensions IS NOT NULL;
-- Supporting indexes for common query patterns CREATE INDEX idx_plans_tenant_project ON nexus.plans (tenant_id, project); CREATE INDEX idx_plans_tenant_verb ON nexus.plans (tenant_id, verb); CREATE INDEX idx_plans_tenant_outcome ON nexus.plans (tenant_id, outcome); CREATE INDEX idx_plans_tenant_created_at ON nexus.plans (tenant_id, created_at DESC); CREATE INDEX idx_plans_tenant_disabled_at ON nexus.plans (tenant_id, disabled_at);

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.plans;
ALTER TABLE nexus.plans NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.plans DISABLE ROW LEVEL SECURITY;
